fn bubble_sort_checksum(a: &[i64], n: i64) -> i64 {
    let mut buf = a[..n as usize].to_vec();
    for i in 0..n as usize {
        for j in 0..(n as usize - 1 - i) {
            if buf[j] > buf[j + 1] { buf.swap(j, j + 1); }
        }
    }
    let mut sum = 0;
    for i in 0..n as usize { sum += i as i64 * buf[i]; }
    sum
}

