def bubble_sort_checksum(a: list, n: int) -> int:
    buf = a[:n]
    for i in range(n):
        for j in range(n - 1 - i):
            if buf[j] > buf[j + 1]:
                buf[j], buf[j + 1] = buf[j + 1], buf[j]
    return sum(i * buf[i] for i in range(n))

JavaScript.source:
function bubble_sort_checksum(a, n) {
  const buf = a.slice(0, n);
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n - 1 - i; j++) {
      if (buf[j] > buf[j + 1]) {
        const tmp = buf[j];
        buf[j] = buf[j + 1];
        buf[j + 1] = tmp;
      }
    }
  }
  let sum = 0;
  for (let i = 0; i < n; i++) {
    sum += i * buf[i];
  }
  return sum;
}

