    let (mut first, mut second) = (a[0], a[1]);
    if second > first { std::mem::swap(&mut first, &mut second); }
    for i in 2..n as usize {
        if a[i] > first { second = first; first = a[i]; }
        else if a[i] > second { second = a[i]; }
    }
    second
}

