function second_largest(a, n) {
  let first = a[0];
  let second = a[1];
  if (second > first) {
    const tmp = first;
    first = second;
    second = tmp;
  }
  for (let i = 2; i < n; i++) {
    if (a[i] > first) {
      second = first;
      first = a[i];
    } else if (a[i] > second) {
      second = a[i];
    }
  }
  return second;
}

