int64_t rotate_left_n(int64_t x, int64_t n, int64_t bits) {
    int64_t width = pow2(bits);
    x = x % width;
    n = n % bits;
    int64_t hi = (x * pow2(n)) % width;
    int64_t lo = x / pow2(bits - n);
    return hi + lo;
}

