C.source:
int64_t tax_bracket(int64_t income) {
    int64_t tax = 0;
    if (income > 8500000) {
        tax += (income - 8500000) * 30 / 100;
        income = 8500000;
    }
    if (income > 4000000) {
        tax += (income - 4000000) * 20 / 100;
        income = 4000000;
    }
    if (income > 1000000) {
        tax += (income - 1000000) * 10 / 100;
    }
    return tax;
}

