C.source:
int64_t chunk_sum_max(const int64_t *a, int64_t n, int64_t k) {
    int64_t window = 0;
    for (int64_t i = 0; i < k; i++) window += a[i];
    int64_t best = window;
    for (int64_t i = k; i < n; i++) {
        window += a[i] - a[i - k];
        if (window > best) best = window;
    }
    return best;
}

