int64_t dedup_sorted_checksum(const int64_t *a, int64_t n) {
    if (n == 0) return 0;
    int64_t sum = 0, pos = 0, prev = a[0];
    for (int64_t i = 1; i < n; i++) {
        if (a[i] != prev) { pos++; sum += pos * a[i]; prev = a[i]; }
    }
    return sum;
}

