int64_t has_pair_sum(const int64_t *a, int64_t n, int64_t target) {
    int64_t lo = 0, hi = n - 1;
    while (lo < hi) {
        int64_t s = a[lo] + a[hi];
        if (s == target) return 1;
        else if (s < target) lo++;
        else hi--;
    }
    return 0;
}

