    let (mut lo, mut hi) = (0i64, n - 1);
    while lo < hi {
        let s = a[lo as usize] + a[hi as usize];
        if s == target { return 1; }
        else if s < target { lo += 1; }
        else { hi -= 1; }
    }
    0
}

