int64_t union_count_sorted(const int64_t *a, int64_t la, const int64_t *b, int64_t lb) {
    int64_t i = 0, j = 0, count = 0;
    while (i < la && j < lb) {
        if (a[i] == b[j]) { count++; i++; j++; }
        else if (a[i] < b[j]) { count++; i++; }
        else { count++; j++; }
    }
    while (i < la) { count++; i++; }
    while (j < lb) { count++; j++; }
    return count;
}

