C.source:
int64_t blackjack_value(const int64_t *cards, int64_t n) {
    int64_t sum = 0, aces = 0;
    for (int64_t i = 0; i < n; i++) {
        int64_t c = cards[i];
        if (c == 1) { aces++; sum += 11; }
        else if (c >= 10) sum += 10;
        else sum += c;
    }
    while (sum > 21 && aces > 0) { sum -= 10; aces--; }
    return sum;
}

C++.source:
std::int64_t blackjack_value(const std::int64_t *cards, std::int64_t n) {
    std::int64_t sum = 0, aces = 0;
    for (std::int64_t i = 0; i < n; i++) {
        std::int64_t c = cards[i];
        if (c == 1) { aces++; sum += 11; }
        else if (c >= 10) sum += 10;
        else sum += c;
    }
    while (sum > 21 && aces > 0) { sum -= 10; aces--; }
    return sum;
}

Rust.source:
fn blackjack_value(cards: &[i64], n: i64) -> i64 {
    let mut sum = 0;
    let mut aces = 0;
    for i in 0..n as usize {
        let c = cards[i];
        if c == 1 { aces += 1; sum += 11; }
        else if c >= 10 { sum += 10; }
        else { sum += c; }
    }
    while sum > 21 && aces > 0 { sum -= 10; aces -= 1; }
    sum
}

Python.source:
def blackjack_value(cards: list, n: int) -> int:
    total = 0
    aces = 0
    for i in range(n):
        c = cards[i]
        if c == 1:
            aces += 1
            total += 11
        elif c >= 10:
            total += 10
        else:
            total += c
    while total > 21 and aces > 0:
        total -= 10
        aces -= 1
    return total

JavaScript.source:
function blackjack_value(cards, n) {
  let total = 0;
  let aces = 0;
  for (let i = 0; i < n; i++) {
    const c = cards[i];
    if (c === 1) {
      aces += 1;
      total += 11;
    } else if (c >= 10) {
      total += 10;
    } else {
      total += c;
    }
  }
  while (total > 21 && aces > 0) {
    total -= 10;
    aces -= 1;
  }
  return total;
}

