int64_t pair_count(const int64_t *a, int64_t n) {
    int64_t count = 0, i = 0;
    while (i < n) {
        int64_t j = i;
        while (j < n && a[j] == a[i]) j++;
        count += (j - i) / 2;
        i = j;
    }
    return count;
}

