    [0, 4, 8], [2, 4, 6],
  ];
  for (let l = 0; l < lines.length; l++) {
    const w = line_winner(board, lines[l][0], lines[l][1], lines[l][2]);
    if (w !== 0) {
      return w;
    }
  }
  return 0;
}

