int64_t euler_totient(int64_t n) {
    int64_t result = n;
    for (int64_t p = 2; p * p <= n; p++) {
        if (n % p == 0) {
            while (n % p == 0) n = n / p;
            result = result - result / p;
        }
    }
    if (n > 1) result = result - result / n;
    return result;
}

