i64 parse_int_signed(const std::string &s) {
    if (s.empty()) return 0;
    bool neg = false;
    size_t start = 0;
    if (s[0] == '-') { neg = true; start = 1; }
    if (start == s.size()) return 0;
    i64 val = 0;
    for (size_t i = start; i < s.size(); i++) {
        char c = s[i];
        if (c < '0' || c > '9') return 0;
        val = val * 10 + (c - '0');
