    start = 1 if neg else 0
    if start == len(s):
        return 0
    val = 0
    for c in s[start:]:
        if not ("0" <= c <= "9"):
            return 0
        val = val * 10 + (ord(c) - 48)
    return -val if neg else val

JavaScript.source:
function parse_int_signed(s) {
  if (s.length === 0) {
    return 0;
  }
  const neg = s[0] === "-";
  const start = neg ? 1 : 0;
  if (start === s.length) {
    return 0;
  }
  let val = 0;
  for (let i = start; i < s.length; i++) {
    const o = s.charCodeAt(i);
    if (o < 48 || o > 57) {
      return 0;
    }
    val = val * 10 + (o - 48);
  }
  return neg ? -val : val;
}

