    std::vector<std::int64_t> buf(a, a + n);
    std::int64_t lo = 0, hi = n - 1;
    bool swapped = true;
    while (swapped) {
        swapped = false;
        for (std::int64_t i = lo; i < hi; i++)
            if (buf[i] > buf[i + 1]) { std::swap(buf[i], buf[i + 1]); swapped = true; }
        if (!swapped) break;
        hi--;
        swapped = false;
        for (std::int64_t i = hi - 1; i >= lo; i--)
            if (buf[i] > buf[i + 1]) { std::swap(buf[i], buf[i + 1]); swapped = true; }
