int64_t comb_sort_checksum(const int64_t *a, int64_t n) {
    int64_t buf[256];
    for (int64_t i = 0; i < n; i++) buf[i] = a[i];
    int64_t gap = n, swapped = 1;
    while (gap > 1 || swapped) {
        gap = (gap * 10) / 13;
        if (gap < 1) gap = 1;
        swapped = 0;
        for (int64_t i = 0; i + gap < n; i++)
            if (buf[i] > buf[i + gap]) {
                int64_t t = buf[i]; buf[i] = buf[i + gap]; buf[i + gap] = t;
                swapped = 1;
            }
    }
    return checksum(buf, n);
}

