int64_t edit_distance(const int64_t *a, int64_t la, const int64_t *b, int64_t lb) {
    int64_t dp[64];
    for (int64_t j = 0; j <= lb; j++) dp[j] = j;
    for (int64_t i = 1; i <= la; i++) {
        int64_t prev = dp[0];
        dp[0] = i;
        for (int64_t j = 1; j <= lb; j++) {
            int64_t tmp = dp[j];
            if (a[i - 1] == b[j - 1]) {
                dp[j] = prev;
            } else {
                int64_t m = dp[j - 1];
                if (dp[j] < m) m = dp[j];
                if (prev < m) m = prev;
                dp[j] = m + 1;
            }
            prev = tmp;
        }
    }
    return dp[lb];
}

