int64_t is_rotation(const int64_t *a, const int64_t *b, int64_t n) {
    if (n == 0) return 1;
    for (int64_t k = 0; k < n; k++) {
        int64_t ok = 1;
        for (int64_t i = 0; i < n; i++) {
            int64_t idx = i + k;
            if (idx >= n) idx -= n;
            if (a[idx] != b[i]) { ok = 0; break; }
        }
        if (ok) return 1;
    }
    return 0;
}

