void initials(const char *name, char *out) {
    size_t pos = 0;
    int in_word = 0;
    for (const char *p = name; *p; p++) {
        if (*p == ' ' || *p == '\t' || *p == '\n') {
            in_word = 0;
        } else if (!in_word) {
            in_word = 1;
            char c = *p;
            out[pos++] = (c >= 'a' && c <= 'z') ? (char)(c - 32) : c;
        }
    }
    out[pos] = '\0';
}

