    for (char c : name) {
        if (std::isspace(static_cast<unsigned char>(c))) {
            in_word = false;
        } else if (!in_word) {
            in_word = true;
            out += (c >= 'a' && c <= 'z') ? static_cast<char>(c - 32) : c;
        }
    }
    return out;
}

