void truncate_ellipsis(const char *s, i64 max, char *out) {
    size_t n = strlen(s);
    if ((i64)n <= max) {
        strcpy(out, s);
        return;
    }
    size_t keep = (size_t)(max - 3);
    memcpy(out, s, keep);
    strcpy(out + keep, "...");
}

