        if (c >= '0' && c <= '9') has_digit = 1;
        else if (c >= 'a' && c <= 'z') has_lower = 1;
        else if (c >= 'A' && c <= 'Z') has_upper = 1;
    }
    return score + has_digit + has_lower + has_upper;
}

