long long power_mod(long long base, long long exp, long long m) {
    long long r = 1;
    base %= m;
    while (exp > 0) {
        if (exp % 2 == 1) r = (r * base) % m;
        exp /= 2;
        base = (base * base) % m;
    }
    return r;
}

