function power_mod(base, exp, m) {
  let r = 1;
  base %= m;
  while (exp > 0) {
    if (exp % 2 === 1) {
      r = (r * base) % m;
    }
    exp = Math.trunc(exp / 2);
    base = (base * base) % m;
  }
